module top_module(
input [1:0] S,
input [3:0] in,
output reg [3:0] obf_Q,
input clk,
input reset
);always @ (posedge clk)
    begin
        if (reset == 1'b1)
            obf_Q <= 4'b0000;
        else if (S == 2'b00)
            begin
                obf_Q[3] <= obf_Q[3];
                obf_Q[2] <= obf_Q[2];
                obf_Q[1] <= obf_Q[1];
                obf_Q[0] <= obf_Q[0];
                end
        else if (S == 2'b01)
            begin
                obf_Q[3] <= 1'b0;
                obf_Q[2] <= obf_Q[3];
                obf_Q[1] <= obf_Q[2];
                obf_Q[0] <= obf_Q[1];
                end
        else if (S == 2'b10)
            begin
                obf_Q[3] <= obf_Q[2];
                obf_Q[2] <= obf_Q[1];
                obf_Q[1] <= obf_Q[0];
                obf_Q[0] <= 1'b0;
                end
        else if (S == 2'b11)
            begin
                obf_Q[3] <= in[3];
                obf_Q[2] <= in[2];
                obf_Q[1] <= in[1];
                obf_Q[0] <= in[0];
                end
    end


endmodule
